import{_ as a,o as e,c as h,e as i}from"./app-def54fd2.js";const r={},d=i('<h1 id="第三方支付对接基础知识" tabindex="-1"><a class="header-anchor" href="#第三方支付对接基础知识" aria-hidden="true">#</a> 第三方支付对接基础知识</h1><h2 id="服务模式" tabindex="-1"><a class="header-anchor" href="#服务模式" aria-hidden="true">#</a> 服务模式</h2><p>直连模式和服务商模式。</p><p>直连模式：商户直接对接微信或者支付宝，需要对接所有的接口。</p><p>服务商模式：提供商户号给你的服务器，即可使用。即子商户申请的appid和mchid提供给服务商。</p><h2 id="下单和支付" tabindex="-1"><a class="header-anchor" href="#下单和支付" aria-hidden="true">#</a> 下单和支付</h2><p>支付功能是基于业务的基础上进行，所以先业务下单。</p><blockquote><p>一些系统有可能下单和支付是一个事务内进行，并不区别业务订单和支付订单。例如扫描支付。</p></blockquote><h2 id="下单未支付" tabindex="-1"><a class="header-anchor" href="#下单未支付" aria-hidden="true">#</a> 下单未支付</h2><p>最简单的处理：每次下单生成一笔新的订单，原来的那个订单就当做废订单。</p><h2 id="支付回调" tabindex="-1"><a class="header-anchor" href="#支付回调" aria-hidden="true">#</a> 支付回调</h2><ol><li>分布式锁保证处理逻辑</li><li>RabbitMQ进行解耦</li></ol><h2 id="退款" tabindex="-1"><a class="header-anchor" href="#退款" aria-hidden="true">#</a> 退款</h2><ol><li>执行退款逻辑之前，先调一下第三方的查询确认状态接口，对方没有那么你必须要求他们提供，只有保证对方明确可以退。</li><li>单独记录退款数据。</li><li>退款是有时限的，例如微信和支付宝是不同的。</li></ol><h2 id="对账" tabindex="-1"><a class="header-anchor" href="#对账" aria-hidden="true">#</a> 对账</h2><p>对账的方法是调微信、支付宝、第三方（如果有）的账单接口，拉取到账单然后进行订单的比对，计算出长款多少，短款多少。</p><h2 id="聚合支付" tabindex="-1"><a class="header-anchor" href="#聚合支付" aria-hidden="true">#</a> 聚合支付</h2><p>一码多付，根据扫码的浏览器AGENT进行下单。</p><blockquote><p>https://juejin.cn/post/7287036223541379126</p></blockquote>',19),t=[d];function c(n,o){return e(),h("div",null,t)}const s=a(r,[["render",c],["__file","第三方支付对接基础知识.html.vue"]]);export{s as default};
